const page = penpotUtils.getPageByName("Desktop");
const intro = penpotUtils.findShape(s => s.name === "Intro", page.root);
const children = penpotUtils.findShapes(s => s.parent?.id === intro.id, page.root);

return {
  intro: { width: intro.width, height: intro.height, x: intro.x, y: intro.y },
  children: children.map(c => ({
    name: c.name,
    type: c.type,
    width: c.width,
    height: c.height,
    x: c.x,
    y: c.y,
    parentX: c.parentX,
    parentY: c.parentY
  }))
};

const page = penpotUtils.getPageByName("Desktop");

// Get Landing frame's Card
const landing = penpotUtils.findShape(s => s.name === "Landing", page.root);
const landingCard = penpotUtils.findShape(s => s.name === "Card" && s.parent?.id === landing.id, page.root);

// Get Top Bubble details (header card)
const topBubble = penpotUtils.findShape(s => s.name === "Top Bubble" && s.parent?.name === "Intro", page.root);
const topBubbleChildren = penpotUtils.findShapes(s => s.parent?.id === topBubble.id, page.root);

return {
  landing: { width: landing.width, height: landing.height },
  landingCard: landingCard ? { width: landingCard.width, height: landingCard.height, parentX: landingCard.parentX, parentY: landingCard.parentY } : null,
  topBubble: { width: topBubble.width, height: topBubble.height, parentX: topBubble.parentX, parentY: topBubble.parentY },
  topBubbleChildren: topBubbleChildren.map(c => ({ name: c.name, type: c.type, width: c.width, height: c.height }))
};

